Sure, here's an example Java code for an Account microservice:

```java
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;

import spark.Request;
import spark.Response;
import spark.Route;
import spark.Spark;

import com.google.gson.Gson;

public class AccountMicroservice {

    private static Map<String, UserAccount> accounts = new HashMap<>();
    private static Gson gson = new Gson();

    public static void main(String[] args) {
        Spark.port(3000);

        // Create account endpoint
        Spark.post("/accounts", new Route() {
            @Override
            public Object handle(Request request, Response response) throws Exception {
                UserAccount account = gson.fromJson(request.body(), UserAccount.class);
                account.setId(UUID.randomUUID().toString());
                accounts.put(account.getId(), account);
                response.status(201);
                return gson.toJson(new SuccessResponse("Account created successfully"));
            }
        });

        // Get account endpoint
        Spark.get("/accounts/:id", new Route() {
            @Override
            public Object handle(Request request, Response response) throws Exception {
                String id = request.params(":id");
                UserAccount account = accounts.get(id);

                if (account != null) {
                    return gson.toJson(account);
                }

                response.status(404);
                return gson.toJson(new ErrorResponse("Account not found"));
            }
        });

        // Update account endpoint
        Spark.put("/accounts/:id", new Route() {
            @Override
            public Object handle(Request request, Response response) throws Exception {
                String id = request.params(":id");
                UserAccount account = accounts.get(id);

                if (account != null) {
                    UserAccount updated = gson.fromJson(request.body(), UserAccount.class);
                    account.setUsername(updated.getUsername());
                    account.setEmail(updated.getEmail());
                    account.setPassword(updated.getPassword());
                    response.status(200);
                    return gson.toJson(new SuccessResponse("Account updated successfully"));
                }

                response.status(404);
                return gson.toJson(new ErrorResponse("Account not found"));
            }
        });

        // Delete account endpoint
        Spark.delete("/accounts/:id", new Route() {
            @Override
            public Object handle(Request request, Response response) throws Exception {
                String id = request.params(":id");
                UserAccount account = accounts.get(id);

                if (account != null) {
                    accounts.remove(id);
                    response.status(200);
                    return gson.toJson(new SuccessResponse("Account deleted successfully"));
                }

                response.status(404);
                return gson.toJson(new ErrorResponse("Account not found"));
            }
        });
    }
}

class UserAccount {

    private String id;
    private String username;
    private String email;
    private String password;

    public UserAccount() {
        // No-arg constructor for Gson
    }

    public UserAccount(String username, String email, String password) {
        this.id = UUID.randomUUID().toString();
        this.username = username;
        this.email = email;
        this.password = password;
    }

    // Getters and setters...

    public String toJson() {
        return new Gson().toJson(this);
    }
}

class SuccessResponse {
    private boolean success = true;
    private String message;

    public SuccessResponse(String message) {
        this.message = message;
    }

    // Getters and setters...
}

class ErrorResponse {
    private boolean success = false;
    private String message;

    public ErrorResponse(String message) {
        this.message = message;
    }

    // Getters and setters...
}
```

This code uses Spark Java web framework to set up endpoints for creating, retrieving, updating, and deleting user accounts. The Account microservice stores the user accounts in a `HashMap`, and uses Gson library to convert Java objects to JSON format. Note that this is a simplified example and you may need to change the implementation to suit your specific use case.
